var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이유리! 멈춰라! 너까지 경찰을 건드리면……!","JPN":"カスカベ！　止まれ！　お前まで警察に手を出したら……！","ENG":"Lee Yuri! Stop! If you also hurt an officer–!","TWN":"李悠麗！住手！連你也襲警的話……！"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"쿨럭! 뭐야, 이건……! 연막탄인가?!","JPN":"ゲホッ！　何だ、これは……！　煙幕弾か！？","ENG":"*Cough!* What's this...?! A smoke grenade?!","TWN":"咳咳！搞什麼？這是……！煙霧彈嗎？！"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"메이드장님, 제 말 들리세요? 대답할 수 있으신가요?","JPN":"メイド長、聞こえますか？　返事はできますか？","ENG":"Chief Maid, can you hear me? Please say something.","TWN":"女僕長，有聽到我的聲音嗎？你可以回答嗎？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"릴리……? 기다리지 않고, 이런 데까지 왜……","JPN":"リリー……？　どうして待たずにこんなところまで……","ENG":"Lily...? Why didn't you wait for me and come all the way here...?","TWN":"莉莉……？你為何不乖乖等著，還跑到這裡……"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"수사를 담당하신 경정님께 동행을 요청드렸습니다.","JPN":"捜査を担当した警視様に同行を要請しました。","ENG":"I asked for the major in charge of the investigation to come with her.","TWN":"我請負責查案的警正讓我一起同行。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"혹시나 했지만 이런 상태이실 줄은……. 정말 깝놀입니다.","JPN":"もしかしてとは思いましたが、こんな状態とは……びっくりぽんです。","ENG":"I knew something was up, but... I'm shook AF seeing your current state.","TWN":"我雖然有心理準備，但沒想到會是這種狀態……真是嚇歪我。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"끔찍하고 흉한 몰골이겠죠…… 메이드장으로서 면목이 없군요.","JPN":"酷い格好ですよね……メイド長として恥ずかしいです。","ENG":"I bet I look horrible right now... I'm ashamed to even call myself Chief Maid.","TWN":"我現在的樣子應該很可怕吧……我沒臉當女僕長。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"가시죠. 경정님이 저들을 막는 동안 여길 빠져나가야 해요.","JPN":"行きましょう。警視様が彼らを留めている間にここから抜け出すべきです。","ENG":"C'mon. We need to get out of here while the major is dealing with them.","TWN":"我們走吧，趁著警正和他們交手時，趕緊離開這裡。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"릴리, 잠시만…… 기다려 주세요……","JPN":"リリー、少しだけ……待ってください……","ENG":"Lily, hold on... just a second...","TWN":"莉莉，等等……先等一下……"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"기계에…… 빛이……","JPN":"機械に……光が……","ENG":"The light... from the machine...","TWN":"機器……光……"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>동력 공급 확인. 암호를 입력해 주십시오.</color>","JPN":"<color=#ffd34c>動力の供給を確認。パスワードを入力してください。</color>","ENG":"<color=#ffd34c>Power sufficient. Please enter the password.</color>","TWN":"<color=#ffd34c>動能供給確認，請輸入密碼。</color>"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L21_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"동력이……? 아무것도 하지 않았는데……?","JPN":"動力が……？　何もしていませんが……？","ENG":"Power...? But I didn't do anything...","TWN":"動能……？但我明明什麼都沒做……？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그 잘난 능력은 언제 쓸 거야? 갑자기 무서워지기라도 했어?","JPN":"あのご大層な能力はいつ使う気？　いきなり怖くなった？","ENG":"So when are you going to use that power of yours? Are you suddenly scared to use it?","TWN":"怎麼不用你那厲害的能力？該不會是突然害怕起來吧？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"어디 지난번처럼 잘난 척 떠들어 봐!","JPN":"この前みたいに偉そうにしゃべってみなさいよ！","ENG":"Where's all the tough talk from last time, huh?!","TWN":"上次不是很囂張嗎！"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"크윽……!","JPN":"くうっ……！","ENG":"Krrgh...!","TWN":"咳……！"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"너처럼 아무 생각 없이 힘을 다루는 얼간이들 때문에!","JPN":"あなたみたいに何も考えずに力を使うバカどものせいで！","ENG":"Because you morons brandish power so irresponsibly!","TWN":"就是有你這種濫用能力的傢伙！"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"내 가족처럼 무고한 사람들이 희생되는 거라고! 알아?!","JPN":"私の家族のような罪のない人たちが犠牲になるのよ！　わかる！？","ENG":"Innocent people like my family have to suffer! You hear me?","TWN":"才會害和我家人一樣無辜的人犧牲！知道嗎？！"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"설마 저 분들이…….","JPN":"まさか、あの方々が……","ENG":"Wait... Are those two...","TWN":"難道他們……"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"부족한 한 걸음은 내가 마련해 뒀어.","JPN":"足りない一歩は私が用意しておいた。","ENG":"I've already prepared the step needed at the last.","TWN":"現在缺的那一步，我已經準備妥當。"},"stage":{"bg":"CAR","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"나머지는……. 자네 손에 달려 있지.","JPN":"後は……君次第だ。","ENG":"The rest... is up to you.","TWN":"剩下的……就掌握在你手裡。"},"stage":{"bg":"CAR","bgm":"THEMA_MILITIA_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"메이드장님, 왜 갑자기 멍 때리시는 거죠?","JPN":"メイド長、どうしていきなりボケっとしているのですか？","ENG":"Chief Maid, why did you space out like that?","TWN":"女僕長，怎麼突然發愣呢？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그 자는 처음부터…… 저 분들의 힘을 동력으로 이용하려고 했던 거예요.","JPN":"あの者は最初から……あの方々の力を動力として利用しようとしていたのです。","ENG":"That man... He was going to use their powers for the machine from the start.","TWN":"原來他從一開始……就打算利用她們的能力來當作動能。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그렇다면 제가 타깃이 되었던 것도 전부……","JPN":"ならば、私がターゲットになったのも全部……","ENG":"Then the reason I was the target...","TWN":"那我會成為目標也都是他……"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"릴리, 지금부터 패널에 제가 하는 말을 입력해 주세요.","JPN":"リリー、今からパネルに私の言葉を入力してください。","ENG":"Lily, head to the panel and enter what I'm about to tell you.","TWN":"莉莉，請你在面板上輸入我現在所說的話。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"메이드장님, 이 장치는 뭔가 불길해요. 연관되지 않는 게 최선입니다.","JPN":"メイド長、この装置は何だか不吉です。かかわらない方がいいと思います。","ENG":"Chief Maid, something doesn't feel right about this machine. I think it's best not to get involved.","TWN":"女僕長，這個裝置感覺不太對勁，還是少碰為妙。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"제 마지막 부탁이 될 수도 있어요.","JPN":"私の最後の頼みになるかもしれません。","ENG":"This could be my last request.","TWN":"這可能是我最後的請求。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님과, 지켜져야 할 모두를 위해서. 부탁드리겠습니다.","JPN":"ご主人様と、守られるべき皆さんのために。お願いいたします。","ENG":"Please. To protect Master and everyone else...","TWN":"為了主人和必須守護的一切，拜託你。"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"알겠습니다. 뭘 입력해야 하죠?","JPN":"わかりました。何を入力すればいいでしょうか。","ENG":"Okay. What do I have to type in?","TWN":"好的，要輸入什麼呢？"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"암호는……","JPN":"パスワードは……","ENG":"The password is...","TWN":"密碼是……"},"stage":{"bg":"TERRA","bgm":"THEMA_MILITIA_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"우리의 안식을 위해.","JPN":"我々の安息のために。","ENG":"For our sanctuary.","TWN":"為了我們的安息。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>암호 확인. 인가자 베로니카. 생체 인증 완료.</color>","JPN":"<color=#ffd34c>パスワードを確認。認可者ベロニカ。生体認証完了。</color>","ENG":"<color=#ffd34c>Password confirmed. Authorizer: Veronica. Biometric authentication complete.</color>","TWN":"<color=#ffd34c>確認密碼，授權人，貝洛妮卡。身分確認完畢。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>공간 붕괴 억제 프로세스 중단.</color>","JPN":"<color=#ffd34c>空間崩壊抑制プロセスを中断。</color>","ENG":"<color=#ffd34c>Aborting Spatial Collapse Suppression process.</color>","TWN":"<color=#ffd34c>停止空間崩壞抑制程序。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>클리포트 게임 최종 시퀀스를 위해, 방호 프로세스로 이행합니다.</color>","JPN":"<color=#ffd34c>クリフォトゲーム最終シークエンスのため、防護プロセスに移行します。</color>","ENG":"<color=#ffd34c>Initiating Protection process for Qliphoth Game Final Sequence.</color>","TWN":"<color=#ffd34c>為逆卡巴拉遊戲最終序列執行防護程序。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};